function solve(n) {
    // Map to store the count of ways each sum can be formed
    const sumCounts = new Map();

    // We need a^3 + b^3 <= n, with 1 <= a <= b.
    // Since a >= 1 and b >= a, the smallest possible sum is 1^3 + 1^3 = 2.
    // The largest possible value for b occurs when a=1, so 1 + b^3 <= n, b^3 <= n-1.
    // b <= cbrt(n-1).

    // Calculate the maximum possible value for b
    // Since n <= 10^9, cbrt(n) <= 1000.
    const maxB = Math.floor(Math.pow(n - 1, 1/3));

    // Iterate over 'a'
    // a^3 + a^3 <= n => 2 * a^3 <= n => a^3 <= n/2 => a <= cbrt(n/2)
    const maxA = Math.floor(Math.pow(n / 2, 1/3));

    for (let a = 1; a <= maxA; a++) {
        const aCubed = a * a * a;

        // Iterate over 'b', starting from 'a'
        // a^3 + b^3 <= n => b^3 <= n - a^3
        const limitBCubed = n - aCubed;
        const maxBForA = Math.floor(Math.pow(limitBCubed, 1/3));

        // b must be at least a, and at most maxBForA
        for (let b = a; b <= maxBForA; b++) {
            const bCubed = b * b * b;
            const sum = aCubed + bCubed;

            if (sum <= n) {
                const currentCount = sumCounts.get(sum) || 0;
                sumCounts.set(sum, currentCount + 1);
            } else {
                // Since b is increasing, if sum > n, subsequent sums for this 'a' will also be > n.
                break;
            }
        }
    }

    // Collect all "good integers" (those with count >= 2)
    const goodNumbers = [];
    for (const [sum, count] of sumCounts.entries()) {
        if (count >= 2) {
            goodNumbers.push(sum);
        }
    }

    // Return the result sorted in ascending order
    return goodNumbers.sort((a, b) => a - b);
}

